  private void UpdateSelectorVisualState(DateTime nowUtc)
  {
    foreach ((string key, PubgPreLobbyEventsWindow.SelectorEntryControls entry) in this._selectorEntries)
    {
      PubgPreLobbyEventsWindow.EventCardMeta card;
      if (this._eventCards.TryGetValue(key, out card))
        this.UpdateSelectorEntryVisual(entry, card, nowUtc);
    }
  }

  private void UpdateSelectorEntryVisual(
    PubgPreLobbyEventsWindow.SelectorEntryControls entry,
    PubgPreLobbyEventsWindow.EventCardMeta card,
    DateTime nowUtc)
  {
    bool flag = string.Equals(entry.EventKey, this._selectedEventKey, StringComparison.Ordinal);
    Color color = PubgPreLobbyEventsWindow.ResolveSelectorAccent(card);
    entry.AccentColor = color;
    entry.IconRect.Texture = this.ResolveSelectorIconTexture(card);
    entry.BannerRect.Texture = this.ResolveSelectorBannerTexture(card);
    entry.TitleLabel.Text = PubgPreLobbyEventsWindow.ResolveLoc(card.TitleKey, card.EventKey);
    entry.StatusChipLabel.Text = this.BuildSelectorStatusText(card, nowUtc);
    ((Control) entry.SelectedIndicator).Visible = flag;
    ((Control) entry.BannerRect).Visible = flag && entry.BannerRect.Texture != null;
    ((Control) entry.RedDot).Visible = card.HasClaimable || card.RedDotOneTime || card.RedDotTasks || card.RedDotMilestones;
    ((Control) entry.Button).MinSize = flag ? new Vector2(0.0f, 72f) : new Vector2(0.0f, 66f);
    ((Control) entry.Button).MaxHeight = 72f;
    entry.ButtonStyle.BorderThickness = new Thickness(flag ? 2f : 1f);
    entry.ButtonStyle.BackgroundColor = flag ? ((Color) ref color).WithAlpha(0.22f) : (entry.Hovered ? Color.FromHex((ReadOnlySpan<char>) "#1A2437", new Color?()) : Color.FromHex((ReadOnlySpan<char>) "#121827", new Color?()));
    entry.ButtonStyle.BorderColor = flag ? ((Color) ref color).WithAlpha(0.95f) : (entry.Hovered ? Color.FromHex((ReadOnlySpan<char>) "#58739A", new Color?()) : Color.FromHex((ReadOnlySpan<char>) "#334A69", new Color?()));
    entry.IndicatorStyle.BackgroundColor = color;
    entry.IndicatorStyle.BorderColor = color;
    entry.StatusChipStyle.BackgroundColor = flag ? ((Color) ref color).WithAlpha(0.28f) : Color.FromHex((ReadOnlySpan<char>) "#1A2231", new Color?());
    entry.StatusChipStyle.BorderColor = flag ? ((Color) ref color).WithAlpha(0.95f) : Color.FromHex((ReadOnlySpan<char>) "#456180", new Color?());
    entry.TitleLabel.FontColorOverride = new Color?(flag ? Color.FromHex((ReadOnlySpan<char>) "#F2F7FF", new Color?()) : Color.FromHex((ReadOnlySpan<char>) "#D2E2F7", new Color?()));
  }

  private string BuildSelectorStatusText(
    PubgPreLobbyEventsWindow.EventCardMeta card,
    DateTime nowUtc)
  {
    DateTime dateTime1 = PubgPreLobbyEventsWindow.EnsureUtc(nowUtc);
    DateTime dateTime2 = PubgPreLobbyEventsWindow.EnsureUtc(card.StartAt);
    if (dateTime2 > dateTime1)
    {
      TimeSpan timeSpan = dateTime2 - dateTime1;
      return timeSpan.TotalDays >= 1.0 ? Loc.GetString("pubg-prelobby-hub-event-card-starts-in-days", new (string, object)[2]
      {
        ("days", (object) (int) timeSpan.TotalDays),
        ("hours", (object) timeSpan.Hours)
      }) : Loc.GetString("pubg-prelobby-hub-event-card-starts-in-hours", new (string, object)[2]
      {
        ("hours", (object) Math.Max(1, (int) timeSpan.TotalHours)),
        ("minutes", (object) Math.Max(0, timeSpan.Minutes))
      });
    }
    if (card.HasClaimable)
      return Loc.GetString("pubg-events-selector-claimable");
    if (!card.EndAt.HasValue)
      return Loc.GetString("pubg-events-selector-open");
    TimeSpan timeSpan1 = PubgPreLobbyEventsWindow.EnsureUtc(card.EndAt.Value) - dateTime1;
    if (timeSpan1 <= TimeSpan.Zero)
      return Loc.GetString("pubg-events-selector-ended");
    return timeSpan1.TotalDays >= 1.0 ? Loc.GetString("pubg-prelobby-hub-event-card-time-left-days", new (string, object)[2]
    {
      ("days", (object) (int) timeSpan1.TotalDays),
      ("hours", (object) timeSpan1.Hours)
    }) : Loc.GetString("pubg-prelobby-hub-event-card-time-left-hours", new (string, object)[2]
    {
      ("hours", (object) Math.Max(1, (int) timeSpan1.TotalHours)),
      ("minutes", (object) Math.Max(0, timeSpan1.Minutes))
    });
  }

  private Texture? ResolveSelectorIconTexture(PubgPreLobbyEventsWindow.EventCardMeta card)
  {
    return this.TryGetTextureCached(this.ResolveSelectorIconPath(card));
  }

  private Texture? ResolveSelectorBannerTexture(PubgPreLobbyEventsWindow.EventCardMeta card)
  {
    string path = PubgPreLobbyEventsWindow.ResolveSelectorBannerPath(card);
    return string.IsNullOrWhiteSpace(path) ? (Texture) null : this.TryGetTextureCached(path);
  }

  private string ResolveSelectorIconPath(PubgPreLobbyEventsWindow.EventCardMeta card)
  {
    if (!string.IsNullOrWhiteSpace(card.SelectorIconPath))
      return card.SelectorIconPath;
    if (string.Equals(card.EventKey, "discord_link_once", StringComparison.OrdinalIgnoreCase))
      return "/Textures/_PUBG/Lobby/Events/event_icon_discord.png";
    if (string.Equals(card.EventKey, "mapper_cookie", StringComparison.OrdinalIgnoreCase))
      return "/Textures/_PUBG/Lobby/Events/event_icon_cookie.png";
    return string.Equals(card.EventKey, "mars_opening", StringComparison.OrdinalIgnoreCase) || string.Equals(card.Kind, "mars", StringComparison.OrdinalIgnoreCase) ? "/Textures/_PUBG/Lobby/Events/event_icon_mars.png" : "/Textures/_PUBG/Lobby/Events/event_icon_case.png";
  }

  private static string? ResolveSelectorBannerPath(PubgPreLobbyEventsWindow.EventCardMeta card)
  {
    return !string.IsNullOrWhiteSpace(card.SelectorBannerPath) ? card.SelectorBannerPath : (string) null;
  }

  private static Color ResolveSelectorAccent(PubgPreLobbyEventsWindow.EventCardMeta card)
  {
    if (!string.IsNullOrWhiteSpace(card.SelectorAccentHex))
    {
      Color? nullable = Color.TryFromHex((ReadOnlySpan<char>) card.SelectorAccentHex);
      if (nullable.HasValue)
        return nullable.Value;
    }
    if (string.Equals(card.EventKey, "discord_link_once", StringComparison.OrdinalIgnoreCase))
      return PubgPreLobbyEventsWindow.SelectorDiscordAccent;
    if (string.Equals(card.EventKey, "mapper_cookie", StringComparison.OrdinalIgnoreCase))
      return PubgPreLobbyEventsWindow.SelectorCookieAccent;
    return string.Equals(card.EventKey, "mars_opening", StringComparison.OrdinalIgnoreCase) || string.Equals(card.Kind, "mars", StringComparison.OrdinalIgnoreCase) ? PubgPreLobbyEventsWindow.SelectorMarsAccent : PubgPreLobbyEventsWindow.SelectorDefaultAccent;
  }

  private void RenderDiscord(PubgDiscordEventStateInfo state, bool eventActive)
  {
    this.DiscordDescriptionLabel.Text = Loc.GetString("pubg-events-discord-description");
    this.DiscordStatusLabel.Text = !state.AlreadyClaimed ? (state.Linked ? Loc.GetString("pubg-events-discord-status-linked") : Loc.GetString("pubg-events-discord-status-not-linked")) : Loc.GetString("pubg-events-discord-status-claimed");
    this.DiscordRewardLabel.Text = this.FormatReward(state.RewardType, state.RewardValue);
    this.DiscordClaimButton.Text = state.AlreadyClaimed ? Loc.GetString("pubg-events-claimed") : Loc.GetString("pubg-events-claim");
    ((BaseButton) this.DiscordClaimButton).Disabled = !eventActive || !state.CanClaim;
  }

  private void RenderMars(PubgMarsEventStateInfo state, bool eventActive)
  {
    this._marsPulseTargets.Clear();
    bool isCookieEvent = PubgPreLobbyEventsWindow.IsCookieEvent(this._currentState?.EventKey);
    this.ConfigureMarsTabs(isCookieEvent);
    this.ApplyMarsLayoutMode(isCookieEvent);
    Texture texture = this.ResolveMainEventIcon(isCookieEvent);
    this.MarsEventIcon.Texture = texture;
    this.MarsTokenIcon.Texture = texture;
    this.MarsRewardsTitleLabel.Text = isCookieEvent ? Loc.GetString("pubg-events-cookie-progress-title") : Loc.GetString("pubg-events-mars-rewards-title");
    string str = state.Wallet.Balance.ToString("N0", (IFormatProvider) CultureInfo.InvariantCulture);
    this.MarsTokenBalanceLabel.Text = Loc.GetString(string.IsNullOrWhiteSpace(state.BalanceLabelKey) ? "pubg-events-mars-token-balance" : state.BalanceLabelKey, new (string, object)[1]
    {
      ("amount", (object) str)
    });
    List<PubgMarsMilestoneInfo> list = state.Milestones.OrderBy<PubgMarsMilestoneInfo, int>((Func<PubgMarsMilestoneInfo, int>) (milestone => milestone.Threshold)).ToList<PubgMarsMilestoneInfo>();
    ((Control) this.MarsMilestoneTrack).RemoveAllChildren();
    if (isCookieEvent)
    {
      ((Control) this.MarsMilestoneTrack).AddChild(this.CreateCookieProgressTrack(state.Points, list, eventActive));
    }
    else
    {
      for (int index = 0; index < list.Count; ++index)
      {
        if (index > 0)
        {
          PubgMarsMilestoneInfo marsMilestoneInfo = list[index - 1];
          ((Control) this.MarsMilestoneTrack).AddChild(this.CreateMilestoneConnector((marsMilestoneInfo.IsClaimed || marsMilestoneInfo.IsClaimable || state.Points >= marsMilestoneInfo.Threshold) & (list[index].IsClaimed || list[index].IsClaimable || state.Points >= list[index].Threshold)));
        }
        ((Control) this.MarsMilestoneTrack).AddChild(this.CreateMilestoneCard(list[index], state.Points, eventActive));
      }
    }
    ((Control) this.MarsLoginTaskList).RemoveAllChildren();
    if (!isCookieEvent)
    {
      foreach (PubgMarsTaskInfo loginTask in state.LoginTasks)
        ((Control) this.MarsLoginTaskList).AddChild(this.CreateTaskRow(loginTask, eventActive, state.TaskRewardLabelKey));
      if (state.LoginTasks.Count == 0)
        ((Control) this.MarsLoginTaskList).AddChild((Control) new Label()
        {
          Text = Loc.GetString("pubg-events-empty"),
          FontColorOverride = new Color?(Color.FromHex((ReadOnlySpan<char>) "#97A9C4", new Color?()))
        });
    }
    ((Control) this.MarsChallengeTaskList).RemoveAllChildren();
    foreach (PubgMarsTaskInfo challengeTask in state.ChallengeTasks)
      ((Control) this.MarsChallengeTaskList).AddChild(isCookieEvent ? this.CreateCookieTaskRow(challengeTask, eventActive, state.TaskRewardLabelKey) : this.CreateTaskRow(challengeTask, eventActive, state.TaskRewardLabelKey));
    if (state.ChallengeTasks.Count != 0)
      return;
    string emptyKey = isCookieEvent ? "pubg-events-cookie-no-challenges" : "pubg-events-empty";
    BoxContainer challengeTaskList = this.MarsChallengeTaskList;
    object obj;
    if (!isCookieEvent)
      obj = (object) new Label()
      {
        Text = Loc.GetString(emptyKey),
        FontColorOverride = new Color?(Color.FromHex((ReadOnlySpan<char>) "#97A9C4", new Color?()))
      };
    else
      obj = (object) this.CreateCookieEmptyChallengesPanel(emptyKey);
    ((Control) challengeTaskList).AddChild((Control) obj);
  }

  private void ConfigureMarsTabs(bool isCookieEvent)
  {
    if (isCookieEvent)
    {
      this.MarsTabContainer.SetTabVisible(0, false);
      this.MarsTabContainer.SetTabVisible(1, true);
      this.MarsTabContainer.SetTabTitle(1, Loc.GetString("pubg-events-cookie-tab-daily"));
      this.MarsTabContainer.CurrentTab = 1;
    }
    else
    {
      this.MarsTabContainer.SetTabVisible(0, true);
      this.MarsTabContainer.SetTabVisible(1, true);
      this.MarsTabContainer.SetTabTitle(0, Loc.GetString("pubg-events-tab-login"));
      this.MarsTabContainer.SetTabTitle(1, Loc.GetString("pubg-events-tab-challenge"));
    }
  }

  private void ApplyMarsLayoutMode(bool isCookieEvent)
  {
    if (isCookieEvent)
    {
      ((Control) this.MarsProgressPanel).MinSize = new Vector2(0.0f, 360f);
      this.MarsMilestoneScroll.HScrollEnabled = false;
      this.MarsMilestoneScroll.VScrollEnabled = true;
      this.MarsMilestoneTrack.Orientation = (BoxContainer.LayoutOrientation) 1;
      this.MarsMilestoneTrack.SeparationOverride = new int?(0);
      ((Control) this.MarsMilestoneTrack).HorizontalExpand = true;
      ((Control) this.MarsMilestoneTrack).VerticalExpand = true;
      ((Control) this.MarsTasksPanel).MinSize = new Vector2(0.0f, 240f);
    }
    else
    {
      ((Control) this.MarsProgressPanel).MinSize = new Vector2(0.0f, 320f);
      this.MarsMilestoneScroll.HScrollEnabled = true;
      this.MarsMilestoneScroll.VScrollEnabled = false;
      this.MarsMilestoneTrack.Orientation = (BoxContainer.LayoutOrientation) 0;
      this.MarsMilestoneTrack.SeparationOverride = new int?(6);
      ((Control) this.MarsMilestoneTrack).HorizontalExpand = true;
      ((Control) this.MarsMilestoneTrack).VerticalExpand = false;
      ((Control) this.MarsTasksPanel).MinSize = Vector2.Zero;
    }
  }

