  private string FormatReward(string rewardType, string rewardValue)
  {
    string str;
    if (rewardType != null)
    {
      switch (rewardType.Length)
      {
        case 4:
          switch (rewardType[0])
          {
            case 'i':
              if (rewardType == "item")
              {
                str = Loc.GetString("pubg-events-reward-item", new (string, object)[1]
                {
                  ("id", (object) this.ResolveRewardItemName(rewardValue))
                });
                goto label_21;
              }
              break;
            case 't':
              if (rewardType == "tier")
              {
                str = Loc.GetString("pubg-events-reward-tier", new (string, object)[1]
                {
                  ("id", (object) rewardValue)
                });
                goto label_21;
              }
              break;
          }
          break;
        case 5:
          switch (rewardType[0])
          {
            case 'c':
              if (rewardType == "coins")
              {
                str = Loc.GetString("pubg-events-reward-coins", new (string, object)[1]
                {
                  ("amount", (object) rewardValue)
                });
                goto label_21;
              }
              break;
            case 'e':
              if (rewardType == "emote")
              {
                str = Loc.GetString("pubg-events-reward-emote", new (string, object)[1]
                {
                  ("id", (object) rewardValue)
                });
                goto label_21;
              }
              break;
            case 's':
              if (rewardType == "scrap")
              {
                str = Loc.GetString("pubg-events-reward-scrap", new (string, object)[1]
                {
                  ("amount", (object) rewardValue)
                });
                goto label_21;
              }
              break;
          }
          break;
        case 6:
          if (rewardType == "recipe")
          {
            str = Loc.GetString("pubg-events-reward-recipe", new (string, object)[1]
            {
              ("id", (object) rewardValue)
            });
            goto label_21;
          }
          break;
        case 10:
          if (rewardType == "permission")
          {
            str = Loc.GetString("pubg-events-reward-permission", new (string, object)[1]
            {
              ("id", (object) rewardValue)
            });
            goto label_21;
          }
          break;
        case 12:
          if (rewardType == "premiumCoins")
          {
            str = Loc.GetString("pubg-events-reward-premium", new (string, object)[1]
            {
              ("amount", (object) rewardValue)
            });
            goto label_21;
          }
          break;
      }
    }
    str = Loc.GetString("pubg-events-reward-generic", new (string, object)[2]
    {
      ("type", (object) rewardType),
      ("value", (object) rewardValue)
    });
label_21:
    return str;
  }

  private string GetMilestoneClaimButtonText(bool claimed, string rewardType, string rewardValue)
  {
    if (claimed)
      return Loc.GetString("pubg-events-claimed");
    if (!(rewardType == "coins") && !(rewardType == "scrap") && !(rewardType == "premiumCoins"))
      return Loc.GetString("pubg-events-claim");
    return Loc.GetString("pubg-events-claim-with-amount", new (string, object)[1]
    {
      ("amount", (object) PubgPreLobbyEventsWindow.FormatNumericRewardAmount(rewardValue))
    });
  }

  private static string FormatNumericRewardAmount(string rawValue)
  {
    long result;
    return long.TryParse(rawValue, NumberStyles.Integer, (IFormatProvider) CultureInfo.InvariantCulture, out result) ? result.ToString("N0", (IFormatProvider) CultureInfo.InvariantCulture) : rawValue;
  }

  public void SetError(string text) => this.ErrorLabel.Text = text;

  public void ShowLoadingState(string eventKey)
  {
    this._currentState = (PubgEventDetailInfo) null;
    this._selectedEventKey = eventKey;
    this.ErrorLabel.Text = string.Empty;
    PubgPreLobbyEventsWindow.EventCardMeta eventCardMeta1;
    if (this._eventCards.TryGetValue(eventKey, out eventCardMeta1))
    {
      this.EventTitleLabel.Text = PubgPreLobbyEventsWindow.ResolveLoc(eventCardMeta1.TitleKey, eventKey);
      this.EventDescriptionLabel.Text = PubgPreLobbyEventsWindow.ResolveLoc(eventCardMeta1.DescriptionKey, Loc.GetString("pubg-events-loading"));
      this.UpdateEventTimingLabels(eventCardMeta1.StartAt, eventCardMeta1.EndAt);
    }
    else
    {
      this.EventTitleLabel.Text = eventKey;
      this.EventDescriptionLabel.Text = Loc.GetString("pubg-events-loading");
      this.EventPeriodLabel.Text = Loc.GetString("pubg-events-period-loading");
    }
    bool flag1 = string.Equals(eventKey, "discord_link_once", StringComparison.OrdinalIgnoreCase);
    PubgPreLobbyEventsWindow.EventCardMeta eventCardMeta2;
    if (!flag1 && this._eventCards.TryGetValue(eventKey, out eventCardMeta2))
      flag1 = string.Equals(eventCardMeta2.Kind, "one_time", StringComparison.OrdinalIgnoreCase);
    bool flag2 = PubgPreLobbyEventsWindow.IsCookieEvent(eventKey);
    this._marsPulseTargets.Clear();
    ((Control) this.EventDescriptionLabel).Visible = flag1 | flag2;
    if (flag2)
      this.EventDescriptionLabel.Text = Loc.GetString("pubg-events-cookie-support-description");
    ((Control) this.DiscordSection).Visible = flag1;
    ((Control) this.MarsSection).Visible = !flag1;
    if (((Control) this.DiscordSection).Visible)
      this.RenderDiscordLoading();
    if (((Control) this.MarsSection).Visible)
      this.RenderMarsLoading();
    this.UpdateSelectorVisualState(DateTime.UtcNow);
  }

  private void SetupTextures()
  {
    this._coinTexture = this.TryGetPrototypeIcon("SpaceCash") ?? this.TryGetTexture("/Textures/_PUBG/Lobby/PreLobby/prelobby_icon_coin.png");
    this._scrapTexture = this.TryGetPrototypeIcon("SheetSteel1") ?? this.TryGetTexture("/Textures/_PUBG/Lobby/PreLobby/prelobby_icon_scrap.png");
    this._premiumTexture = this.TryGetPrototypeIcon("MaterialDiamond1") ?? this.TryGetTexture("/Textures/_PUBG/Lobby/PreLobby/prelobby_icon_premium.png");
    this._itemTexture = this.TryGetTexture("/Textures/_PUBG/Lobby/PreLobby/prelobby_icon_gift.png") ?? this.TryGetTexture("/Textures/_PUBG/Lobby/Events/event_icon_case.png");
    this._fallbackTexture = this.TryGetTexture("/Textures/_PUBG/Lobby/Events/event_icon_case.png");
  }

  private Texture? TryGetPrototypeIcon(string prototypeId)
  {
    EntityPrototype entityPrototype;
    return !this._prototypeManager.TryIndex<EntityPrototype>(prototypeId, ref entityPrototype) ? (Texture) null : ((IDirectionalTextureProvider) this._entityManager.System<SpriteSystem>().GetPrototypeIcon(entityPrototype)).Default;
  }

  private Texture? GetRewardIcon(string rewardType, string rewardValue)
  {
    Texture rewardIcon;
    if (rewardType != null)
    {
      switch (rewardType.Length)
      {
        case 4:
          switch (rewardType[0])
          {
            case 'i':
              if (rewardType == "item")
              {
                rewardIcon = this.TryGetPrototypeIcon(rewardValue) ?? this._itemTexture ?? this._fallbackTexture;
                goto label_21;
              }
              break;
            case 't':
              if (rewardType == "tier")
              {
                rewardIcon = this._itemTexture ?? this._fallbackTexture;
                goto label_21;
              }
              break;
          }
          break;
        case 5:
          switch (rewardType[0])
          {
            case 'c':
              if (rewardType == "coins")
              {
                rewardIcon = this._coinTexture;
                goto label_21;
              }
              break;
            case 'e':
              if (rewardType == "emote")
              {
                rewardIcon = this._itemTexture ?? this._fallbackTexture;
                goto label_21;
              }
              break;
            case 's':
              if (rewardType == "scrap")
              {
                rewardIcon = this._scrapTexture;
                goto label_21;
              }
              break;
          }
          break;
        case 6:
          if (rewardType == "recipe")
          {
            rewardIcon = this._itemTexture ?? this._fallbackTexture;
            goto label_21;
          }
          break;
        case 10:
          if (rewardType == "permission")
          {
            rewardIcon = this._itemTexture ?? this._fallbackTexture;
            goto label_21;
          }
          break;
        case 12:
          if (rewardType == "premiumCoins")
          {
            rewardIcon = this._premiumTexture;
            goto label_21;
          }
          break;
      }
    }
