  private bool UpdateMarsPulse(double deltaSeconds)
  {
    if (this._marsPulseTargets.Count == 0)
      return false;
    this._marsPulseTime += (float) deltaSeconds;
    for (int index = 0; index < this._marsPulseTargets.Count; ++index)
    {
      PubgPreLobbyEventsWindow.MarsPulseTarget marsPulseTarget = this._marsPulseTargets[index];
      float num = (float) (0.5 + (double) MathF.Sin((float) ((double) this._marsPulseTime * 3.4000000953674316 + (double) index * 0.550000011920929)) * 0.5);
      float t1 = (float) (0.18000000715255737 + (double) num * 0.51999998092651367);
      float t2 = (float) (0.05000000074505806 + (double) num * 0.15999999642372131);
      if (marsPulseTarget.Hovered)
      {
        t1 = Math.Clamp(t1 + 0.24f, 0.0f, 0.95f);
        t2 = Math.Clamp(t2 + 0.12f, 0.0f, 0.45f);
        marsPulseTarget.CardStyle.BorderThickness = new Thickness(2f);
      }
      else
        marsPulseTarget.CardStyle.BorderThickness = new Thickness(1f);
      marsPulseTarget.CardStyle.BorderColor = PubgPreLobbyEventsWindow.LerpColor(marsPulseTarget.BaseCardBorder, marsPulseTarget.PulseCardBorder, t1);
      marsPulseTarget.CardStyle.BackgroundColor = PubgPreLobbyEventsWindow.LerpColor(marsPulseTarget.BaseCardBackground, marsPulseTarget.PulseCardBackground, t2);
    }
    return true;
  }

  private static Color LerpColor(Color from, Color to, float t)
  {
    t = Math.Clamp(t, 0.0f, 1f);
    return new Color(from.R + (to.R - from.R) * t, from.G + (to.G - from.G) * t, from.B + (to.B - from.B) * t, from.A + (to.A - from.A) * t);
  }

